import json
# Collect all stored var_call_* variables available in this environment
g = globals()
vars_list = [name for name in g.keys() if name.startswith('var_call_')]
records = []
for name in vars_list:
    try:
        v = g[name]
        # v could be a string (file path) for large results or a Python object list
        if isinstance(v, str):
            # If it's a file path to JSON, try to load
            try:
                with open(v,'r') as f:
                    v2 = json.load(f)
                v = v2
            except Exception:
                # keep as string
                continue
        # v expected to be a list of dicts
        if isinstance(v, list):
            for rec in v:
                if isinstance(rec, dict) and 'symbol' in rec:
                    sym = rec.get('symbol')
                    up = rec.get('up_count')
                    down = rec.get('down_count')
                    # normalize
                    def to_num(x):
                        if x is None: return None
                        if isinstance(x,(int,float)): return float(x)
                        if isinstance(x,str):
                            s = x.strip()
                            if s.lower()=='nan': return None
                            try:
                                return float(s)
                            except:
                                return None
                        return None
                    upn = to_num(up)
                    downn = to_num(down)
                    records.append({'symbol':sym,'up':upn,'down':downn})
    except Exception:
        pass
# Filter and sort
valid = [r for r in records if r['up'] is not None and r['down'] is not None and r['up']>r['down']]
valid.sort(key=lambda x: x['up'], reverse=True)
top5 = valid[:5]
# Load stockinfo file for company descriptions - variable var_call_F7ARdSLa3CfMEqYQoQGvzIcb is a file path
info_path = globals().get('var_call_F7ARdSLa3CfMEqYQoQGvzIcb')
company_map = {}
if isinstance(info_path, str):
    try:
        with open(info_path,'r') as f:
            info = json.load(f)
        for rec in info:
            company_map[rec['Symbol']] = rec.get('Company Description','')
    except Exception:
        pass
# Prepare final names
names = [company_map.get(r['symbol'], r['symbol']) for r in top5]
print('__RESULT__:')
print(json.dumps(names))

